.forumheader{border:1px solid #aaa;background-color:#f9f9f9;margin-top:1em;padding:12px}.forumlist td.forum_edited a{color:black;text-decoration:none }.forumlist td.forum_title a{padding-left:20px}.forumlist td.forum_title a.forum_new{font-weight:bold;background:url(http://starter.wikia.com/images/4/4e/Forum_new.gif) center left no-repeat;padding-left:20px}.forumlist td.forum_title a.forum_new:visited{font-weight:normal;background:none;padding-left:20px}.forumlist th.forum_title{padding-left:20px}